const lead = items[0].json;
// IDEMPOTENCY: if ghl_contact_id already set, skip create — update only path later
return [{
  json: {
    lead,
    needs_ghl_create: !lead.ghl_contact_id,
    is_staging: lead.is_staging === true || lead.environment === 'staging'
  }
}];

const ctx = $('GHL Idempotency Check').item.json;
const lead = ctx.lead;
let ghlId = lead.ghl_contact_id;
let ghlOk = true;
let ghlError = null;

if (ctx.needs_ghl_create) {
  const resp = items[0].json;
  const statusCode = resp.statusCode || 200;
  const body = resp.body || resp;
  if (statusCode === 429) {
    ghlOk = false;
    ghlError = 'rate_limited';
  } else if (statusCode >= 400) {
    ghlOk = false;
    ghlError = body.message || body.error || `HTTP ${statusCode}`;
  } else {
    ghlId = body.contact?.id || body.id || null;
    if (!ghlId) { ghlOk = false; ghlError = 'No contact id in GHL response'; }
  }
}

return [{ json: { lead, ghl_contact_id: ghlId, ghl_ok: ghlOk, ghl_error: ghlError, is_staging: ctx.is_staging } }];

const ghl = $('Parse GHL').item.json;
const lead = ghl.lead;
const tpl = items[0].json;

if (!tpl || !tpl.template_key || tpl.status !== 'approved') {
  return [{
    json: {
      blocked: true,
      lead_id: lead.id,
      reason: 'No approved first-touch template. Agent 4 will not freelance sales copy.',
      ghl_contact_id: ghl.ghl_contact_id
    }
  }];
}

const booking = $env.BOOKING_LINK || 'https://example.com/book';
const rendered = String(tpl.body)
  .replaceAll('{{name}}', lead.name || 'there')
  .replaceAll('{{campaign_name}}', lead.campaign_name || 'our program')
  .replaceAll('{{booking_link}}', booking);

const subject = tpl.subject
  ? String(tpl.subject)
      .replaceAll('{{name}}', lead.name || 'there')
      .replaceAll('{{campaign_name}}', lead.campaign_name || 'our program')
  : null;

// Staging: never send real outreach — log only
if (ghl.is_staging || lead.environment === 'staging') {
  return [{
    json: {
      blocked: false,
      dry_run: true,
      lead_id: lead.id,
      campaign_id: lead.campaign_id,
      ghl_contact_id: ghl.ghl_contact_id,
      template_key: tpl.template_key,
      template_version: tpl.version,
      channel: tpl.channel,
      subject,
      rendered_body: rendered,
      ghl_workflow_id: tpl.ghl_workflow_id || $env.GHL_DEFAULT_WORKFLOW_ID || null,
      days_after_prev: tpl.days_after_prev || 2,
      sequence_order: tpl.sequence_order || 1
    }
  }];
}

return [{
  json: {
    blocked: false,
    dry_run: false,
    lead_id: lead.id,
    campaign_id: lead.campaign_id,
    ghl_contact_id: ghl.ghl_contact_id,
    template_key: tpl.template_key,
    template_version: tpl.version,
    channel: tpl.channel,
    subject,
    rendered_body: rendered,
    ghl_workflow_id: tpl.ghl_workflow_id || $env.GHL_DEFAULT_WORKFLOW_ID || null,
    days_after_prev: tpl.days_after_prev || 2,
    sequence_order: tpl.sequence_order || 1
  }
}];

