const lead = $('Load Due Follow-ups').item.json;
if (!lead || !lead.id) {
  return [{ json: { skip: true, reason: 'no_due_leads' } }];
}
const tpl = items[0].json;
const noResp = Number(lead.computed_no_response_days || lead.no_response_days || 0);
const temp = lead.new_temperature || lead.temperature || 'warm';

// Stall path: after last template or cold for too long → nurture/requeue (never abandon)
if (!tpl || !tpl.template_key) {
  return [{
    json: {
      skip: false,
      action: 'nurture_requeue',
      lead_id: lead.id,
      campaign_id: lead.campaign_id,
      temperature: temp,
      no_response_days: noResp,
      reason: 'sequence_exhausted_or_no_approved_template'
    }
  }];
}

if (temp === 'cold' && noResp >= 7) {
  return [{
    json: {
      skip: false,
      action: 'nurture_requeue',
      lead_id: lead.id,
      campaign_id: lead.campaign_id,
      temperature: 'cold',
      no_response_days: noResp,
      reason: 'no_response_cold'
    }
  }];
}

const booking = $env.BOOKING_LINK || 'https://example.com/book';
const rendered = String(tpl.body)
  .replaceAll('{{name}}', lead.name || 'there')
  .replaceAll('{{campaign_name}}', lead.campaign_name || 'our program')
  .replaceAll('{{booking_link}}', booking);

const dry = lead.is_staging === true || lead.environment === 'staging';
return [{
  json: {
    skip: false,
    action: 'follow_up',
    dry_run: dry,
    lead_id: lead.id,
    campaign_id: lead.campaign_id,
    ghl_contact_id: lead.ghl_contact_id,
    temperature: temp,
    no_response_days: noResp,
    template_key: tpl.template_key,
    template_version: tpl.version,
    channel: tpl.channel,
    rendered_body: rendered,
    sequence_order: tpl.sequence_order,
    days_after_prev: tpl.days_after_prev || 2,
    ghl_workflow_id: tpl.ghl_workflow_id || null
  }
}];

